SET search_path TO fleet, public;

-- ── 0. Flotte supplémentaire ──────────────────────────────────────────────────
VALUES ('f1111111-f111-f111-f111-000000000003','Flotte Inter-urbaine Yaoundé','22222222-0002-0002-0002-000000000001',NOW())
ON CONFLICT (id) DO NOTHING;

-- ── 1. VÉHICULES supplémentaires ─────────────────────────────────────────────
ON CONFLICT (id) DO NOTHING;

-- ── 2. USERS + DRIVERS supplémentaires ───────────────────────────────────────
ON CONFLICT (id) DO NOTHING;

ON CONFLICT (user_id) DO NOTHING;

-- ── 3. TRIPS (20) ─────────────────────────────────────────────────────────────
ON CONFLICT (id) DO NOTHING;

-- ── 4. INCIDENTS (20) ─────────────────────────────────────────────────────────
ON CONFLICT (id) DO NOTHING;

-- ── 5. MAINTENANCES (20) ──────────────────────────────────────────────────────
ON CONFLICT (id) DO NOTHING;

-- ── 6. FUEL RECHARGES (20) ────────────────────────────────────────────────────
ON CONFLICT (id) DO NOTHING;

-- ── 7. DÉPENSES (20) ─────────────────────────────────────────────────────────
ON CONFLICT (id) DO NOTHING;

-- ── 8. BUDGETS (6 — colonnes exactes sans is_exceeded) ───────────────────────
ON CONFLICT ON CONSTRAINT uq_budget_entity_month DO NOTHING;

-- ── 9. PLANNINGS + AFFECTATIONS ───────────────────────────────────────────────
ON CONFLICT (id) DO NOTHING;

ON CONFLICT (id) DO NOTHING;

-- ── Vérification finale ──────────────────────────────────────────────────────
SELECT t, cnt FROM (
  SELECT 'vehicles' t, count(*) cnt FROM fleet.vehicles
  UNION ALL SELECT 'drivers', count(*) FROM fleet.drivers
  UNION ALL SELECT 'trips', count(*) FROM fleet.trips
  UNION ALL SELECT 'incidents', count(*) FROM fleet.incidents
  UNION ALL SELECT 'maintenances', count(*) FROM fleet.maintenances
  UNION ALL SELECT 'fuel_recharges', count(*) FROM fleet.fuel_recharges
  UNION ALL SELECT 'expenses', count(*) FROM fleet.expenses
  UNION ALL SELECT 'budgets', count(*) FROM fleet.budgets
  UNION ALL SELECT 'schedules', count(*) FROM fleet.schedules
  UNION ALL SELECT 'assignments', count(*) FROM fleet.assignments
) sub ORDER BY t;
